return [{ json: {
  week: 'July 7–11, 2026',
  wins: [
    'Recurring tasks frontend completed and in QA — on track for July 31 GA',
    'Customer discovery call: confirmed NPS hypothesis — onboarding drop-off at step 3',
    'Board deck draft done 2 days early'
  ],
  struggles: [
    'Two team members blocked by missing PM deliverables (design spec, API contract) — I should have unblocked these Tuesday, not Friday',
    'Spent 3h on email/Slack that could have been batched into 1h',
    'Did not write spec for bulk actions — carries over for the 2nd consecutive week'
  ],
  big_decisions: [
    { decision: 'Decided not to pursue enterprise tier pricing update this quarter — too many moving parts', confidence: 'medium', reversible: true },
    { decision: 'Hired James Kim as design lead — will start Aug 1', confidence: 'high', reversible: false }
  ],
  key_metrics_vs_last_week: [
    { metric: 'MRR', current: 38400, previous: 37200, unit: 'USD' },
    { metric: 'Signups', current: 142, previous: 129, unit: 'accounts' },
    { metric: 'NPS', current: 41, previous: 38, unit: 'score' },
    { metric: 'Support tickets', current: 23, previous: 31, unit: 'tickets' }
  ],
  energy_level: 'medium',
  focus_rating: 3,
  what_i_would_do_differently: 'Unblock team members daily — not at end-of-week standup'
} }];

const ctx = $input.first().json;
const winsText = ctx.wins.map(w => `  ✓ ${w}`).join('
');
const strugglesText = ctx.struggles.map(s => `  ✗ ${s}`).join('
');
const decisionsText = ctx.big_decisions.map(d => `  [${d.confidence.toUpperCase()} confidence | ${d.reversible?'reversible':'irreversible'}] ${d.decision}`).join('
');
const metricsText = ctx.key_metrics_vs_last_week.map(m => { const chg = m.current - m.previous; const pct = parseFloat(((chg/m.previous)*100).toFixed(1)); return `  ${m.metric}: ${m.current}${m.unit} (${chg>=0?'+':''}${chg} / ${pct>=0?'+':''}${pct}%)`; }).join('
');
const system = `You are an executive coach and founder advisor. You help founders extract insight from their week — not just reflect, but spot patterns, identify leverage points, and set sharper intentions. You are direct and honest, not flattering. Return ONLY valid JSON.`;
const user = `Weekly review for the week of ${ctx.week}:

Wins:
${winsText}

Struggles:
${strugglesText}

Big decisions:
${decisionsText}

Metrics vs last week:
${metricsText}

Energy level: ${ctx.energy_level} | Focus rating: ${ctx.focus_rating}/5
What I'd do differently: ${ctx.what_i_would_do_differently}

Return JSON:
{
  "week_headline": "string — 8-12 word summary of the week",
  "key_pattern": "string — the most important behavioural or operational pattern you observed",
  "leverage_point": "string — the one thing to change next week that will have the highest impact",
  "metric_commentary": "string — brief insight on the most important metric movement",
  "decision_quality_note": "string — feedback on the quality of decisions made this week",
  "energy_note": "string — honest assessment of energy and what it signals",
  "next_week_intention": "string — a single clear intention for next week (not a todo list)",
  "question_to_sit_with": "string — a coaching question to reflect on over the weekend"
}`;
return [{ json: { ctx, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Reflection Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.week_headline) return [{ json: { _error: true, reason: 'Missing week_headline' } }];
return [{ json: { _error: false, reflection: parsed, ctx: upstream.ctx, meta: { week: upstream.ctx.week, generated_at: new Date().toISOString() } } }];
